$ErrorActionPreference = "Stop"

$project = "C:\Users\arauj\grafica-flash"

if (!(Test-Path $project)) {
  Write-Host "Projeto nao encontrado em $project" -ForegroundColor Red
  exit 1
}

Set-Location $project

$utf8NoBom = New-Object System.Text.UTF8Encoding($false)

function Write-Base64File($relativePath, $base64Content) {
  $target = Join-Path $project $relativePath
  $directory = Split-Path $target -Parent

  New-Item -ItemType Directory -Force $directory | Out-Null

  $bytes = [System.Convert]::FromBase64String($base64Content.Trim())
  $content = [System.Text.Encoding]::UTF8.GetString($bytes)

  [System.IO.File]::WriteAllText($target, $content, $utf8NoBom)
}


Write-Base64File "lib\security.ts" @"

"@

Write-Base64File "middleware.ts" @"

"@

Write-Base64File "app\cadastro\page.tsx" @"

"@

# Ajusta a loja pública para ler somente views públicas seguras, não tabelas completas.
$loja = Join-Path $project "app\orcamento\[slug]\page.tsx"
if (Test-Path $loja) {
  $content = [System.IO.File]::ReadAllText($loja)
  $content = $content.Replace(".from('companies')", ".from('public_company_profiles')")
  $content = $content.Replace('.from("companies")', '.from("public_company_profiles")')
  $content = $content.Replace(".from('products')", ".from('public_store_products')")
  $content = $content.Replace('.from("products")', '.from("public_store_products")')
  [System.IO.File]::WriteAllText($loja, $content, $utf8NoBom)
}

# Aumenta o tamanho do token da proposta, se a função antiga existir.
$proposta = Join-Path $project "app\painel\proposta\[id]\page.tsx"
if (Test-Path $proposta) {
  $content = [System.IO.File]::ReadAllText($proposta)
  $content = $content.Replace("slice(0, 12)", "slice(0, 24)")
  [System.IO.File]::WriteAllText($proposta, $content, $utf8NoBom)
}

# Protege variáveis locais contra commit acidental.
$gitignore = Join-Path $project ".gitignore"
if (!(Test-Path $gitignore)) {
  [System.IO.File]::WriteAllText($gitignore, "", $utf8NoBom)
}

$gitignoreContent = [System.IO.File]::ReadAllText($gitignore)
$linhas = @(
  ".env",
  ".env.local",
  ".env*.local",
  "!.env.example"
)

foreach ($linha in $linhas) {
  if ($gitignoreContent -notmatch [regex]::Escape($linha)) {
    Add-Content -Path $gitignore -Value $linha
  }
}

Remove-Item -Recurse -Force ".next" -ErrorAction SilentlyContinue

Write-Host "Seguranca fase 2 instalada: headers, validacoes, views publicas e patches de privacidade." -ForegroundColor Green
Write-Host "Agora rode: npm run build" -ForegroundColor Yellow
